const envelope = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const event = envelope.event;
const payload = envelope.payload || {};
if (event !== 'message') {
  return [];
}
if (payload.fromMe === true) {
  return [];
}
const chatId = String(payload.from || payload.chatId || payload.key?.remoteJid || '').trim();
if (!chatId || /@g\.us$/i.test(chatId)) {
  return [];
}
const mediaUrl = String(payload.media?.url || '').trim();
const mediaMimeType = String(payload.media?.mimetype || '').trim();
const hasImage = Boolean(payload.hasMedia && mediaUrl && /^image\//i.test(mediaMimeType));
const messageText = [
  payload.body,
  payload.text?.body,
  payload.message?.conversation,
  payload.message?.extendedTextMessage?.text,
  payload.message?.imageMessage?.caption,
  payload.message?.videoMessage?.caption
].find((value) => typeof value === 'string' && value.trim()) || '';
if (!messageText && !hasImage) {
  return [];
}
const senderId = String(
  payload.remoteJidAlt ||
  payload._data?.remoteJidAlt ||
  payload._data?.id?.remoteJidAlt ||
  payload.author ||
  payload.participant ||
  payload.key?.participant ||
  chatId
).trim();
const phone = senderId
  .replace(/@s\.whatsapp\.net$/i, '')
  .replace(/@c\.us$/i, '')
  .replace(/@lid$/i, '');
const normalizedText = String(messageText || '').trim();
return [
  {
    json: {
      session: envelope.session || $json.session || 'default',
      event,
      phone,
      chatId,
      senderId,
      text: normalizedText,
      logText: normalizedText || (hasImage ? '[imagem recebida]' : ''),
      hasMedia: Boolean(payload.hasMedia),
      hasImage,
      mediaUrl,
      mediaMimeType,
      rawPayload: payload,
      rawEnvelope: envelope
    }
  }
];

const incoming = $item(0).$node["Normalize Incoming Message"].json;
const config = $item(0).$node["Get MVP Config"].json;
const state = $json || {};
return [
  {
    json: {
      ...incoming,
      fallbackMessage: config.DefaultFallbackMessage,
      defaultDelayDays: Number(config.DefaultDelayDays || 3),
      initialMessage: config.InitialWhatsAppMessage,
      conversationState: state.CurrentState || 'idle',
      conversationFlow: state.ActiveFlow || '',
      conversationLastIntent: state.LastIntent || '',
      conversationContext: state.Context || {},
      conversationStateFound: Boolean(state.Found),
      conversationStateExpiresAt: state.ExpiresAt || null,
      conversationStateTtlHours: Number(config.ConversationStateTtlHours || 12)
    }
  }
];

const normalized = ($json.text || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/\s+/g, ' ').trim();
const exactCommands = new Set(['parar', 'stop', 'descadastrar', 'cancelar cobranca', 'remover meu numero', 'nao enviar', 'nao mande']);
const isOptOutCommand = exactCommands.has(normalized);
return [{ json: { ...$json, isOptOutCommand } }];

const context = $item(0).$node["Detect Opt Out Command"].json;
return [
  {
    json: {
      ...context,
      optOutResult: $json,
      replyText: 'Entendido. Nao enviaremos novas cobrancas automaticas por este WhatsApp. Se quiser retomar no futuro, fale com um operador.',
      logIntent: 'opt_out'
    }
  }
];

const digits = ($json.text || '').replace(/\D/g, '');
const match = digits.match(/(\d{14}|\d{11})/);
return [
  {
    json: {
      ...$json,
      document: match ? match[1] : ''
    }
  }
];

const context = $item(0).$node["Prepare Classification Context"].json;
const content = $json.choices?.[0]?.message?.content || '{"intent":"default_operator","reason":"empty"}';
let parsed;
try {
  parsed = JSON.parse(content);
} catch (error) {
  parsed = { intent: 'default_operator', reason: 'invalid_json' };
}
const rawText = String(context.text || '').trim();
const normalized = rawText.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/\s+/g, ' ').trim();
const hasDocument = Boolean(context.document);
const onlyDigitsOrPunctuation = /^[\d\s.\-\/]+$/.test(rawText);
const shortDocumentReply = rawText.length <= 22;
const documentOnlyMessage = hasDocument && onlyDigitsOrPunctuation && shortDocumentReply;
const state = context.conversationState || 'idle';
const activeFlow = context.conversationFlow || '';
const secondViaKeywords = ['boleto', '2 via', 'segunda via', 'reenviar', 'reenvio', 'linha digitavel'];
const dueDateKeywords = ['alteracao de vencimento', 'alterar vencimento', 'mudar vencimento', 'prorrogar vencimento', 'prorrogar vencimento', 'boleto venceu', 'boleto vencido', 'solicitar alteracao de vencimento'];
const handoffKeywords = ['humano', 'atendente', 'operador', 'pessoa', 'suporte'];
const knowledgeKeywords = ['qual', 'quais', 'onde', 'como', 'quando', 'endereco', 'telefone', 'email', 'e-mail', 'horario', 'empresa', 'nippon', '?'];
const tokenCount = normalized ? normalized.split(' ').filter(Boolean).length : 0;
const mentionsSecondVia = secondViaKeywords.some((keyword) => normalized.includes(keyword));
const mentionsDueDate = dueDateKeywords.some((keyword) => normalized.includes(keyword)) || (normalized.includes('vencimento') && (normalized.includes('alter') || normalized.includes('venc')));
const requestsHuman = handoffKeywords.some((keyword) => normalized.includes(keyword));
const looksLikeKnowledgeQuery = knowledgeKeywords.some((keyword) => rawText.toLowerCase().includes(keyword) || normalized.includes(keyword)) || tokenCount >= 4;
const menuOption = normalized.match(/^(1|2|3)$/)?.[1] || '';
let intent = 'default_operator';
let classificationReason = 'fallback_default';
let nextFlow = activeFlow || '';
if (state === 'awaiting_menu_selection') {
  if (menuOption === '1') {
    intent = 'ask_document';
    nextFlow = 'segunda_via_boleto';
    classificationReason = 'menu_option_second_via';
  } else if (menuOption === '2') {
    intent = 'ask_document';
    nextFlow = 'alteracao_vencimento';
    classificationReason = 'menu_option_due_date';
  } else if (menuOption === '3') {
    intent = 'default_operator';
    classificationReason = 'menu_option_operator';
  } else if (requestsHuman) {
    intent = 'default_operator';
    classificationReason = 'menu_handoff_keyword';
  } else if (mentionsDueDate) {
    nextFlow = 'alteracao_vencimento';
    intent = hasDocument ? 'segunda_via_boleto' : 'ask_document';
    classificationReason = hasDocument ? 'menu_due_date_with_document' : 'menu_due_date_without_document';
  } else if (mentionsSecondVia || context.hasImage || documentOnlyMessage) {
    nextFlow = 'segunda_via_boleto';
    intent = hasDocument || context.hasImage || documentOnlyMessage ? (hasDocument ? 'segunda_via_boleto' : 'ask_document') : 'ask_document';
    classificationReason = hasDocument ? 'menu_second_via_with_document' : 'menu_second_via_without_document';
  } else if (looksLikeKnowledgeQuery) {
    intent = 'default_operator';
    classificationReason = 'menu_free_question';
  } else {
    intent = 'show_welcome_menu';
    classificationReason = 'menu_repeat';
  }
} else if (requestsHuman) {
  intent = 'default_operator';
  classificationReason = 'handoff_keyword';
} else if (documentOnlyMessage) {
  intent = 'segunda_via_boleto';
  nextFlow = activeFlow || 'segunda_via_boleto';
  classificationReason = 'document_only_message';
} else if (hasDocument && (mentionsDueDate || activeFlow === 'alteracao_vencimento')) {
  intent = 'segunda_via_boleto';
  nextFlow = 'alteracao_vencimento';
  classificationReason = 'due_date_with_document';
} else if (!hasDocument && mentionsDueDate) {
  intent = 'ask_document';
  nextFlow = 'alteracao_vencimento';
  classificationReason = 'due_date_without_document';
} else if (hasDocument && (mentionsSecondVia || state === 'awaiting_document' || state === 'awaiting_document_second_via' || activeFlow === 'segunda_via_boleto' || context.documentSource === 'image_paddle_ocr' || context.documentSource === 'image_ollama')) {
  intent = 'segunda_via_boleto';
  nextFlow = activeFlow || 'segunda_via_boleto';
  classificationReason = state === 'awaiting_document' || state === 'awaiting_document_second_via' ? 'state_resume_with_document' : 'document_with_receivables_context';
} else if (!hasDocument && (mentionsSecondVia || state === 'awaiting_document' || state === 'awaiting_document_second_via' || activeFlow === 'segunda_via_boleto')) {
  intent = 'ask_document';
  nextFlow = activeFlow || 'segunda_via_boleto';
  classificationReason = state === 'awaiting_document' || state === 'awaiting_document_second_via' ? 'state_waiting_for_document' : 'boleto_keyword_without_document';
} else {
  intent = parsed.intent || 'default_operator';
  classificationReason = parsed.reason || 'llm_fallback';
  if (!hasDocument && intent === 'segunda_via_boleto') {
    intent = 'ask_document';
    nextFlow = 'segunda_via_boleto';
  } else if (hasDocument && intent === 'segunda_via_boleto') {
    nextFlow = activeFlow || 'segunda_via_boleto';
  }
}
return [
  {
    json: {
      ...context,
      intent,
      nextFlow,
      resolvedFlow: nextFlow || activeFlow || 'segunda_via_boleto',
      classificationReason,
      debugIntentOverride: documentOnlyMessage,
      llmSuggestedIntent: parsed.intent || 'default_operator'
    }
  }
];

const flow = $json.nextFlow || $json.resolvedFlow || $json.conversationFlow || 'segunda_via_boleto';
const replyText = flow === 'alteracao_vencimento'
  ? 'Para solicitar a alteracao de vencimento, informe o CPF ou CNPJ vinculado ao cadastro. Se preferir, envie uma foto legivel do boleto.'
  : 'Para localizar seu boleto, por favor informe o CPF ou CNPJ vinculado ao cadastro. Se preferir, envie uma foto legivel do boleto.';
return [
  {
    json: {
      ...$json,
      replyText,
      logIntent: flow === 'alteracao_vencimento' ? 'alteracao_vencimento' : 'ask_document'
    }
  }
];

const context = $item(0).$node["Parse Intent"].json;
const flow = context.resolvedFlow || context.nextFlow || context.conversationFlow || 'segunda_via_boleto';
return [
  {
    json: {
      ...context,
      replyText: 'Nao consegui validar o CPF/CNPJ com o telefone desta conversa. Por favor, revise os dados ou aguarde atendimento humano.',
      logIntent: flow === 'alteracao_vencimento' ? 'alteracao_vencimento' : 'segunda_via_boleto'
    }
  }
];

const context = $item(0).$node["Parse Intent"].json;
const flow = context.resolvedFlow || context.nextFlow || context.conversationFlow || 'segunda_via_boleto';
const boletos = $json.Boletos || [];
const boleto = boletos[0];
if (!boleto) {
  return [
    {
      json: {
        ...context,
        canUpdate: false,
        replyText: flow === 'alteracao_vencimento' ? 'Nao localizamos um boleto elegivel para alteracao de vencimento neste momento. Em breve um operador dara continuidade ao atendimento.' : 'Nao localizamos um boleto para reenvio neste momento. Em breve um operador dara continuidade ao atendimento.',
        logIntent: flow === 'alteracao_vencimento' ? 'alteracao_vencimento' : 'segunda_via_boleto'
      }
    }
  ];
}
const currentDate = new Date(`${boleto.Vencimento}T00:00:00Z`);
currentDate.setUTCDate(currentDate.getUTCDate() + Number(context.defaultDelayDays || 3));
const newDueDate = currentDate.toISOString().slice(0, 10);
return [
  {
    json: {
      ...context,
      resolvedFlow: flow,
      canUpdate: true,
      boletoId: boleto.Identificador,
      tenantId: 1,
      currentDueDate: boleto.Vencimento,
      newDueDate,
      linhaDigitavel: boleto.LinhaDigitavel,
      logIntent: flow === 'alteracao_vencimento' ? 'alteracao_vencimento' : 'segunda_via_boleto'
    }
  }
];

const context = $item(0).$node["Prepare Due Date Update"].json;
const flow = context.resolvedFlow || context.nextFlow || context.conversationFlow || 'segunda_via_boleto';
const closingText = 'Agradecemos o seu contato com a Nippon Elevadores. Este atendimento foi encerrado. Se precisar, estamos a disposicao.';
const replyText = flow === 'alteracao_vencimento'
  ? `Solicitacao concluida. Prorrogamos o vencimento do seu boleto para ${context.newDueDate}. Linha digitavel: ${context.linhaDigitavel}\n\n${closingText}`
  : `Localizamos seu boleto e prorrogamos o vencimento para ${context.newDueDate}. Linha digitavel: ${context.linhaDigitavel}\n\n${closingText}`;
return [
  {
    json: {
      ...context,
      replyText,
      logIntent: flow === 'alteracao_vencimento' ? 'alteracao_vencimento' : 'segunda_via_boleto'
    }
  }
];

return [
  {
    json: {
      ...$json,
      replyText: 'Nao consegui identificar o CPF ou CNPJ na imagem. Se preferir, envie o documento digitado ou uma foto mais legivel do boleto.',
      logIntent: 'ask_document'
    }
  }
];

const nextItem = { ...$json };
if (nextItem.documentSource === 'image_ollama' && !String(nextItem.text || '').trim()) {
  nextItem.text = 'foto do boleto';
}
return [{ json: nextItem }];

const normalized = ($json.text || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/\s+/g, ' ').trim();
const digits = normalized.replace(/\D/g, '');
const hasDocument = /(\d{14}|\d{11})/.test(digits);
const secondViaKeywords = ['boleto', '2 via', 'segunda via', 'reenviar', 'reenvio', 'linha digitavel'];
const dueDateKeywords = ['alteracao de vencimento', 'alterar vencimento', 'mudar vencimento', 'prorrogar vencimento', 'prorrogar vencimento', 'boleto venceu', 'boleto vencido'];
const handoffKeywords = ['humano', 'atendente', 'operador', 'suporte'];
const greetingKeywords = ['oi', 'ola', 'bom dia', 'boa tarde', 'boa noite', 'preciso de ajuda', 'quero ajuda', 'quero falar com voces', 'quero atendimento', 'ola tudo bem'];
const hasDirectIntent = Boolean($json.hasImage || hasDocument || secondViaKeywords.some((keyword) => normalized.includes(keyword)) || dueDateKeywords.some((keyword) => normalized.includes(keyword)) || handoffKeywords.some((keyword) => normalized.includes(keyword)));
const isGenericGreeting = greetingKeywords.some((keyword) => normalized === keyword || normalized.includes(keyword));
const shouldSendWelcome = ($json.conversationState === 'idle' || !$json.conversationStateFound) && !hasDirectIntent && Boolean(normalized) && isGenericGreeting;
return [{ json: { ...$json, shouldSendWelcome } }];
